module div_8bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [3:0] cnt;
    reg [15:0] SR;
    reg [7:0] NEG_DIVISOR;
    reg [1:0] state;
    reg start_cnt;

    parameter IDLE = 2'b00;
    parameter SUB = 2'b01;
    parameter SELECT = 2'b10;
    parameter SHIFT = 2'b11;
    parameter DONE = 2'b100;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            cnt <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (opn_valid && !res_valid) begin
                        cnt <= 1;
                        start_cnt <= 1;
                        state <= SUB;
                    end
                end
            endcase
        end
    end

    wire [15:0] sub_result;
    wire carry_out;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            cnt <= 0;
        end else begin
            case (state)
                SUB: begin
                    if (cnt == 8) begin
                        cnt <= 1;
                        start_cnt <= 0;
                        state <= DONE;
                    end else begin
                        if (sign) begin
                            if (dividend[7] == divisor[7]) begin
                                NEG_DIVISOR <= divisor;
                            end else begin
                                NEG_DIVISOR <= -divisor;
                            end
                        end else begin
                            NEG_DIVISOR <= divisor;
                        end
                        SR <= {SR[14:0], 1'b0};
                        SR[15:8] <= dividend[7:0];
                        sub_result <= SR - {1'b0, NEG_DIVISOR};
                        carry_out <= sub_result[15];
                        if (carry_out == 1'b0) begin
                            SR <= sub_result;
                        end
                        state <= SELECT;
                    end
                end
            endcase
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            cnt <= 0;
        end else begin
            case (state)
                SELECT: begin
                    if (carry_out == 1'b1) begin
                        SR <= {SR[14:0], 1'b1};
                    end
                    state <= SHIFT;
                end
            endcase
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            cnt <= 0;
        end else begin
            case (state)
                SHIFT: begin
                    if (start_cnt == 1'b1) begin
                        cnt <= cnt + 1;
                    end
                    if (cnt == 8) begin
                        state <= DONE;
                    end else begin
                        state <= SUB;
                    end
                end
            endcase
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 1'b0;
            result <= 16'b0;
        end else begin
            if (state == DONE) begin
                res_valid <= 1'b1;
                result <= {SR[7:0], 8'b0};
            end else begin
                if (res_valid && res_ready) begin
                    res_valid <= 1'b0;
                end
            end
        end
    end

endmodule
